queries.sparql:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?roletype WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCharacters ?child ; p:hasScreenplays ?parent . } GROUP BY ?child }
  ?child p:roleType ?roletype .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Screenplay } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?title ?roletype WHERE {
  ?screenplays_characters a :Screenplays_Characters .
  ?characters a :Character .
  ?screenplays_characters p:hasCharacters ?characters .
  ?screenplays a :Screenplay .
  ?screenplays_characters p:hasScreenplays ?screenplays .
  ?screenplays p:title ?title .
  ?characters p:roleType ?roletype .
} }
  collective: { SELECT ?roletype WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCharacters ?child ; p:hasScreenplays ?parent . } GROUP BY ?child }
  ?child p:roleType ?roletype .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Screenplay } }
  FILTER(?nf = ?total)
} }
}
